        // Validate and sanitize URL before processing
        URL parsedUrl;
        try {
            parsedUrl = new URL(userUrl);

            // Validate protocol
            if (!ALLOWED_PROTOCOLS.contains(parsedUrl.getProtocol().toLowerCase())) {
                return null;
            }

            // Validate host
            if (!isHostAllowed(parsedUrl.getHost())) {
                return null;
            }

