        CloseableHttpClient httpClient = null;
        CloseableHttpResponse response = null;

        try {
            // Create HttpClient with security configurations
            httpClient = HttpClients.custom()
                .disableRedirectHandling()  // Disable automatic redirects to prevent redirect attacks
                .build();

            RequestConfig config = RequestConfig.custom()
                    .setConnectTimeout(CONNECT_TIMEOUT)
                    .setSocketTimeout(SOCKET_TIMEOUT)
                    .setRedirectsEnabled(false)  // Explicitly disable redirects
                    .build();

            HttpGet httpGet = new HttpGet(parsedUrl.toString());
            httpGet.setConfig(config);

