            httpGet.setHeader("User-Agent", "UrlFetchService/1.0");

            // Prevent content type sniffing
            httpGet.setHeader("X-Content-Type-Options", "nosniff");

            response = httpClient.execute(httpGet);

            int statusCode = response.getStatusLine().getStatusCode();

            // Handle redirects manually with validation
            if (statusCode == HttpStatus.SC_MOVED_TEMPORARILY || 
                statusCode == HttpStatus.SC_MOVED_PERMANENTLY ||
                statusCode == HttpStatus.SC_SEE_OTHER ||
                statusCode == HttpStatus.SC_TEMPORARY_REDIRECT) {

                String location = response.getFirstHeader("Location").getValue();
                if (location != null && !location.isEmpty()) {
                    // Recursively fetch with validation
                    return fetchUrlContent(location);
                }
            }

            if (statusCode != HttpStatus.SC_OK) {
                return null;
            }

            HttpEntity entity = response.getEntity();
            if (entity == null) {
                return null;
            }

            // Check content length to prevent DoS
            if (entity.getContentLength() > MAX_CONTENT_SIZE) {
                return null;
            }

            // Read content with size limit
            String content = EntityUtils.toString(entity, "UTF-8");

            // Additional size check for compressed content
