                if (httpClient != null) {
                    httpClient.close();
                }
            } catch (IOException e) {
                // Log this exception in production
            }
        }
    }

    /**
     * Validates if the host is allowed to be accessed
     * 
     * @param host the host to validate
     * @return true if allowed, false otherwise
     */
    private boolean isHostAllowed(String host) {
        if (host == null || host.isEmpty()) {
            return false;
        }

        // Check against blocked domains
        String hostLower = host.toLowerCase();
        for (String blocked : BLOCKED_DOMAINS) {
            if (hostLower.equals(blocked) || hostLower.endsWith("." + blocked)) {
                return false;
            }
        }

        // Resolve host to IP and check for private IPs
        try {
            InetAddress address = InetAddress.getByName(host);

            // Check if IP is private/internal
            if (isPrivateIP(address.getHostAddress())) {
                return false;
            }

            // Additional checks for loopback and link-local addresses
            if (address.isLoopbackAddress() || 
                address.isLinkLocalAddress() || 
                address.isSiteLocalAddress()) {
                return false;
            }

        } catch (UnknownHostException e) {
            return false;
        }

        return true;
    }

