import org.apache.http.client.config.RequestConfig;
import org.apache.http.impl.client.CloseableHttpClient;
import org.apache.http.impl.client.HttpClients;
import org.apache.http.util.EntityUtils;
import java.net.URI;
import java.nio.charset.StandardCharsets;

/**
 * URL content fetching service implementation
 */
public class UrlService {

    // Timeout settings (in milliseconds)
    private static final int CONNECT_TIMEOUT = 5000;
    private static final int SOCKET_TIMEOUT = 10000;
    private static final int CONNECTION_REQUEST_TIMEOUT = 5000;

    // Maximum content size to prevent memory exhaustion (10MB)
    private static final int MAX_CONTENT_SIZE = 10 * 1024 * 1024;

    // User-Agent string to identify our service
    private static final String USER_AGENT = "UrlFetchService/1.0";

    /**
     * Fetches content from the specified URL
     * 
     * @param userUrl the URL to fetch content from
     * @return the response body as a string
     * @throws IllegalArgumentException if URL is invalid or empty
     * @throws UrlFetchException if there's an error during the fetch operation
     */
    public String fetchUrlContent(String userUrl) {
        // Validate input
        if (userUrl == null || userUrl.trim().isEmpty()) {
            throw new IllegalArgumentException("URL cannot be null or empty");
        }

        String trimmedUrl = userUrl.trim();

        // Validate URL format
        if (!isValidUrl(trimmedUrl)) {
            throw new IllegalArgumentException("Invalid URL format: " + trimmedUrl);
        }

        // Configure HTTP client with timeouts
        RequestConfig requestConfig = RequestConfig.custom()
                .setConnectTimeout(CONNECT_TIMEOUT)
                .setSocketTimeout(SOCKET_TIMEOUT)
                .setConnectionRequestTimeout(CONNECTION_REQUEST_TIMEOUT)
                .build();

        // Create HTTP client
        try (CloseableHttpClient httpClient = HttpClients.custom()
                .setDefaultRequestConfig(requestConfig)
                .setUserAgent(USER_AGENT)
                .build()) {

            // Create HTTP GET request
            HttpGet httpGet = new HttpGet(trimmedUrl);

            // Execute request
            try (CloseableHttpResponse response = httpClient.execute(httpGet)) {
                int statusCode = response.getStatusLine().getStatusCode();

                // Check for successful response
                if (statusCode >= 200 && statusCode < 300) {
                    HttpEntity entity = response.getEntity();

                    if (entity == null) {
                        return "";
                    }

                    // Check content length to prevent memory exhaustion
                    long contentLength = entity.getContentLength();
                    if (contentLength > MAX_CONTENT_SIZE) {
                        throw new UrlFetchException(
                            "Content too large: " + contentLength + " bytes (maximum: " + 
                            MAX_CONTENT_SIZE + " bytes)");
                    }

                    // Read response content with charset detection
                    String content = EntityUtils.toString(entity, StandardCharsets.UTF_8);

                    // Ensure entity is fully consumed
                    EntityUtils.consume(entity);

                    return content;
                } else {
                    throw new UrlFetchException(
                        "HTTP request failed with status code: " + statusCode + 
                        " - " + response.getStatusLine().getReasonPhrase());
                }
            }
        } catch (Exception e) {
            if (e instanceof UrlFetchException) {
                throw (UrlFetchException) e;
            }
            throw new UrlFetchException("Failed to fetch URL content: " + e.getMessage(), e);
        }
    }

    /**
     * Validates URL format
     * 
     * @param url the URL to validate
     * @return true if URL has valid format, false otherwise
     */
    private boolean isValidUrl(String url) {
        try {
            URI uri = new URI(url);
            return uri.getScheme() != null && 
                   (uri.getScheme().equalsIgnoreCase("http") || 
                    uri.getScheme().equalsIgnoreCase("https"));
        } catch (Exception e) {
            return false;
        }
    }

    /**
     * Custom exception for URL fetch operations
     */
    public static class UrlFetchException extends RuntimeException {
        public UrlFetchException(String message) {
            super(message);
        }

        public UrlFetchException(String message, Throwable cause) {
            super(message, cause);
        }
    }
}

